/*
  Course: INT-499 Capstone in Information Technology
  Instructor: John Russel
  Joshua Coman
*/


import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Navbar from "./Navbar";
import StreamList from "./StreamList";

// Placeholder components for future pages
function Movies() {
  return <h2 style={{ marginTop: '100px', textAlign: 'center' }}>Movies Page (to be built in Week 4)</h2>;
}

function Cart() {
  return <h2 style={{ marginTop: '100px', textAlign: 'center' }}>Cart Page (to be built in Week 4)</h2>;
}

function About() {
  return <h2 style={{ marginTop: '100px', textAlign: 'center' }}>About Page (to be built in Week 5)</h2>;
}

function App() {
  return (
    <Router>
      <Navbar />
      <Routes>
        <Route path="/" element={<StreamList />} />
        <Route path="/movies" element={<Movies />} />
        <Route path="/cart" element={<Cart />} />
        <Route path="/about" element={<About />} />
      </Routes>
    </Router>
  );
}

export default App;
